// game-of-life.spec.ts
import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  it.todo("should return an empty array for an empty grid");
  it.todo("should let a single cell die (underpopulation: 0 neighbors)");
  it.todo(
    "should let two neighboring cells die (underpopulation: 1 neighbor each)"
  );
  it.todo("should keep a live cell with 2 live neighbors alive (survival)");
  it.todo("should keep a live cell with 3 live neighbors alive (survival)");
  it.todo(
    "should let a live cell with 4 live neighbors die (overpopulation)"
  );
  it.todo(
    "should bring a dead cell with exactly 3 live neighbors to life (reproduction)"
  );
  it.todo("should keep a block still life unchanged");
  it.todo(
    "should oscillate a vertical blinker to a horizontal blinker (negative coordinates)"
  );
});
